import FundCard from "./FundCard";
import {
  funds_1,
  funds_2,
  funds_3,
  funds_4,
  funds_5,
  funds_6,
  funds_7,
  funds_8,
} from "../../assets/home";

const cards = [
  {
    id: 1,
    highlight: "Sheet Metal Fabrication",
    meta: "Core service",
    description:
      "High-quality sheet metal components with cutting, forming, shaping and assembling as per customer drawings and specifications.",
    image: funds_1,
    badge: "Fabrication",
  },
  {
    id: 2,
    highlight: "Laser & Precision Cutting",
    meta: "Tight tolerances",
    description:
      "Accurate, clean cutting for standard and custom sheet metal parts, ensuring repeatable precision for every batch.",
    image: funds_2,
    badge: "Cutting",
  },
  {
    id: 3,
    highlight: "CNC Bending & Forming",
    meta: "Complex profiles",
    description:
      "Modern CNC bending capabilities to achieve exact angles and shapes required for demanding industrial applications.",
    image: funds_3,
    badge: "Bending",
  },
  {
    id: 4,
    highlight: "Welding & Assembly",
    meta: "Ready-to-use parts",
    description:
      "Robust welding and complete assembly solutions that deliver finished components and assemblies ready for your production line.",
    image: funds_4,
    badge: "Welding",
  },
  {
    id: 5,
    highlight: "Custom Job Work",
    meta: "Prototype to volume",
    description:
      "Flexible sheet metal job work for prototypes, small batches and large-scale production tailored to your requirements.",
    image: funds_5,
    badge: "Job Work",
  },
  {
    id: 6,
    highlight: "Component Manufacturing",
    meta: "Brackets, panels & more",
    description:
      "Custom brackets, enclosures, frames, panels and fabricated assemblies for multiple industries and applications.",
    image: funds_6,
    badge: "Components",
  },
  {
    id: 7,
    highlight: "OEM & Industrial Supply",
    meta: "Reliable partner",
    description:
      "Consistent supply of precision sheet metal parts for OEMs and industrial clients with a focus on quality and timelines.",
    image: funds_7,
    badge: "OEM Supply",
  },
  {
    id: 8,
    highlight: "End-to-End Support",
    meta: "Drawing to dispatch",
    description:
      "Support from drawing review and prototyping through production, quality checks and on-time dispatch.",
    image: funds_8,
    badge: "Support",
  },
];

export default function FundCards() {
  return (
    <article className="grid xl:grid-cols-4 lg:grid-cols-3 md:grid-cols-2 grid-cols-1 place-items-center lg:gap-14 gap-4">
      {cards.map((card) => (
        <FundCard key={card.id} card={card} />
      ))}
    </article>
  );
}
